module addN
   #(parameter WID = 4)
    (input wire [WID-1:0] A,
     input wire [WID-1:0] B,
     output wire [WID:0]  Q
     /* */);

    assign Q = A + B;

endmodule // add

module top;

    parameter WID = 4;
    (* PAD="2,3,4,5"*)
    wire [WID-1:0] A;
    (* PAD="6,7,8,9"*)
    wire [WID-1:0] B;
    (* PAD="14,15,16,17,18"*)
    wire [WID:0]  Q;

    addN #(.WID(WID)) usum (.A(A), .B(B), .Q(Q));


endmodule
